import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/assets/01-mcp-simple-diagram.h693H2TV.png",u=JSON.parse('{"title":"What is the Model Context Protocol (MCP)?","description":"Notes on What is the Model Context Protocol (MCP)?.","frontmatter":{"title":"What is the Model Context Protocol (MCP)?","description":"Notes on What is the Model Context Protocol (MCP)?."},"headers":[],"relativePath":"misc/artificial-intelligence/modelcontextprotocol-io-what-is-mcp.md","filePath":"misc/artificial-intelligence/modelcontextprotocol-io-what-is-mcp.md"}'),s={name:"misc/artificial-intelligence/modelcontextprotocol-io-what-is-mcp.md"};function i(l,e,c,d,p,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="what-is-the-model-context-protocol-mcp" tabindex="-1">What is the Model Context Protocol (MCP)? <a class="header-anchor" href="#what-is-the-model-context-protocol-mcp" aria-label="Permalink to &quot;What is the Model Context Protocol (MCP)?&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://modelcontextprotocol.io/docs/getting-started/intro" target="_blank" rel="noreferrer">https://modelcontextprotocol.io/docs/getting-started/intro</a></li><li>Imported: 2026-06-18</li><li>Images: 1 (MCP simple diagram saved under <code>./assets/modelcontextprotocol-io-intro/</code>)</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><blockquote><p><strong>Documentation index:</strong> Fetch the complete documentation index at <a href="https://modelcontextprotocol.io/llms.txt" target="_blank" rel="noreferrer">llms.txt</a> to discover all available pages before exploring further.</p></blockquote><p>MCP (Model Context Protocol) is an open-source standard for connecting AI applications to external systems.</p><p>Using MCP, AI applications like Claude or ChatGPT can connect to data sources (e.g. local files, databases), tools (e.g. search engines, calculators) and workflows (e.g. specialized prompts)—enabling them to access key information and perform tasks.</p><p>Think of MCP like a USB-C port for AI applications. Just as USB-C provides a standardized way to connect electronic devices, MCP provides a standardized way to connect AI applications to external systems.</p><p><img src="'+n+'" alt="MCP connects AI applications to external data sources, tools, and workflows"></p><h3 id="what-can-mcp-enable" tabindex="-1">What can MCP enable? <a class="header-anchor" href="#what-can-mcp-enable" aria-label="Permalink to &quot;What can MCP enable?&quot;">​</a></h3><ul><li>Agents can access your Google Calendar and Notion, acting as a more personalized AI assistant.</li><li>Claude Code can generate an entire web app using a Figma design.</li><li>Enterprise chatbots can connect to multiple databases across an organization, empowering users to analyze data using chat.</li><li>AI models can create 3D designs on Blender and print them out using a 3D printer.</li></ul><h3 id="why-does-mcp-matter" tabindex="-1">Why does MCP matter? <a class="header-anchor" href="#why-does-mcp-matter" aria-label="Permalink to &quot;Why does MCP matter?&quot;">​</a></h3><p>Depending on where you sit in the ecosystem, MCP can have a range of benefits.</p><ul><li><strong>Developers:</strong> MCP reduces development time and complexity when building, or integrating with, an AI application or agent.</li><li><strong>AI applications or agents:</strong> MCP provides access to an ecosystem of data sources, tools and apps which will enhance capabilities and improve the end-user experience.</li><li><strong>End-users:</strong> MCP results in more capable AI applications or agents which can access your data and take actions on your behalf when necessary.</li></ul><h3 id="broad-ecosystem-support" tabindex="-1">Broad ecosystem support <a class="header-anchor" href="#broad-ecosystem-support" aria-label="Permalink to &quot;Broad ecosystem support&quot;">​</a></h3><p>MCP is an open protocol supported across a wide range of clients and servers. AI assistants like <a href="https://claude.com/docs/connectors/building" target="_blank" rel="noreferrer">Claude</a> and <a href="https://developers.openai.com/api/docs/mcp/" target="_blank" rel="noreferrer">ChatGPT</a>, development tools like <a href="https://code.visualstudio.com/docs/copilot/chat/mcp-servers" target="_blank" rel="noreferrer">Visual Studio Code</a>, <a href="https://cursor.com/docs/context/mcp" target="_blank" rel="noreferrer">Cursor</a>, <a href="https://docs.mcpjam.com/getting-started" target="_blank" rel="noreferrer">MCPJam</a>, and many others all support MCP — making it easy to build once and integrate everywhere.</p><h3 id="start-building" tabindex="-1">Start building <a class="header-anchor" href="#start-building" aria-label="Permalink to &quot;Start building&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Description</th><th>Link</th></tr></thead><tbody><tr><td>Build servers</td><td>Create MCP servers to expose your data and tools</td><td><a href="https://modelcontextprotocol.io/docs/develop/build-server" target="_blank" rel="noreferrer">Build servers</a></td></tr><tr><td>Build clients</td><td>Develop applications that connect to MCP servers</td><td><a href="https://modelcontextprotocol.io/docs/develop/build-client" target="_blank" rel="noreferrer">Build clients</a></td></tr><tr><td>Build MCP Apps</td><td>Build interactive apps that run inside AI clients</td><td><a href="https://modelcontextprotocol.io/extensions/apps/overview" target="_blank" rel="noreferrer">Build MCP Apps</a></td></tr></tbody></table><h3 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Topic</th><th>Description</th><th>Link</th></tr></thead><tbody><tr><td>Understand concepts</td><td>Learn the core concepts and architecture of MCP</td><td><a href="https://modelcontextprotocol.io/docs/learn/architecture" target="_blank" rel="noreferrer">Architecture</a></td></tr></tbody></table><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>MCP is an open standard that connects AI apps to external data, tools, and workflows through a common protocol.</li><li>The USB-C analogy captures the goal: one standardized interface instead of bespoke integrations per system.</li><li>The ecosystem spans assistants (Claude, ChatGPT), dev tools (VS Code, Cursor), and server/client builders documented on modelcontextprotocol.io.</li></ul>',22)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
